#include<bits/stdc++.h>
using namespace std;
long long n,m,a[1000005];
bool f(long long x,long long sum=0){
	for(int i=1;i<=n;i++)if(a[i]>x)sum+=a[i]-x;
	return sum<m;
}
int main(void){
    cin>>n>>m;
	long long r=0,l=0;
    for(int i=1;i<=n;i++){
    	cin>>a[i];
    	r=max(r,a[i]);
	}
    while(l<=r){
    	long long mid=(l+r)/2;
        if(f(mid))r=mid-1;
		else l=mid+1;
    }
    cout<<l-1;
    return false;
}
